import { useState } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Alert, AlertDescription } from '@/components/ui/alert';

const passwordSchema = z.object({
  currentPassword: z.string().min(1, 'Current password is required'),
  newPassword: z.string().min(8, 'Password must be at least 8 characters'),
  confirmPassword: z.string(),
}).refine(data => data.newPassword === data.confirmPassword, {
  message: 'Passwords do not match',
  path: ['confirmPassword'],
});

type PasswordFormData = z.infer<typeof passwordSchema>;

export default function SecuritySettings() {
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState(false);
  const [loading, setLoading] = useState(false);
  const [twoFaEnabled, setTwoFaEnabled] = useState(false);

  const { register, handleSubmit, formState: { errors }, reset } = useForm<PasswordFormData>({
    resolver: zodResolver(passwordSchema),
  });

  const onSubmit = async (_data: PasswordFormData) => {
    try {
      setLoading(true);
      setError(null);
      setSuccess(false);

      // TODO: Call API to change password
      console.log('Changing password');
      
      setSuccess(true);
      reset();
      setTimeout(() => setSuccess(false), 3000);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to change password');
    } finally {
      setLoading(false);
    }
  };

  const handle2FAToggle = async () => {
    try {
      setLoading(true);
      // TODO: Call API to toggle 2FA
      setTwoFaEnabled(!twoFaEnabled);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="p-6 max-w-2xl mx-auto space-y-6">
      <div>
        <h1 className="text-3xl font-bold">Security Settings</h1>
        <p className="text-gray-600 mt-2">Manage your security preferences</p>
      </div>

      {error && (
        <Alert variant="destructive">
          <AlertDescription>{error}</AlertDescription>
        </Alert>
      )}

      {success && (
        <Alert className="border-green-200 bg-green-50">
          <AlertDescription className="text-green-800">
            Settings updated successfully!
          </AlertDescription>
        </Alert>
      )}

      {/* Two-Factor Authentication */}
      <div className="p-4 border rounded-lg">
        <div className="flex justify-between items-center mb-4">
          <div>
            <h3 className="font-semibold">Two-Factor Authentication</h3>
            <p className="text-sm text-gray-600">Add an extra layer of security to your account</p>
          </div>
          <Button
            variant={twoFaEnabled ? 'destructive' : 'default'}
            onClick={handle2FAToggle}
            disabled={loading}
          >
            {twoFaEnabled ? 'Disable 2FA' : 'Enable 2FA'}
          </Button>
        </div>
        <p className="text-sm text-gray-600">
          Status: {twoFaEnabled ? <span className="text-green-600 font-semibold">Enabled</span> : <span className="text-red-600 font-semibold">Disabled</span>}
        </p>
      </div>

      {/* Change Password */}
      <div className="space-y-4">
        <h3 className="font-semibold text-lg">Change Password</h3>
        
        <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
          <div>
            <label className="block text-sm font-medium mb-2">Current Password</label>
            <Input
              type="password"
              placeholder="••••••••"
              {...register('currentPassword')}
              disabled={loading}
            />
            {errors.currentPassword && <p className="text-red-500 text-sm mt-1">{errors.currentPassword.message}</p>}
          </div>

          <div>
            <label className="block text-sm font-medium mb-2">New Password</label>
            <Input
              type="password"
              placeholder="••••••••"
              {...register('newPassword')}
              disabled={loading}
            />
            {errors.newPassword && <p className="text-red-500 text-sm mt-1">{errors.newPassword.message}</p>}
          </div>

          <div>
            <label className="block text-sm font-medium mb-2">Confirm New Password</label>
            <Input
              type="password"
              placeholder="••••••••"
              {...register('confirmPassword')}
              disabled={loading}
            />
            {errors.confirmPassword && <p className="text-red-500 text-sm mt-1">{errors.confirmPassword.message}</p>}
          </div>

          <Button type="submit" disabled={loading}>
            {loading ? 'Updating...' : 'Change Password'}
          </Button>
        </form>
      </div>

      {/* Active Sessions */}
      <div className="p-4 border rounded-lg">
        <h3 className="font-semibold mb-4">Active Sessions</h3>
        <div className="space-y-2">
          <div className="p-2 bg-gray-50 rounded">
            <p className="text-sm font-medium">Current Session</p>
            <p className="text-xs text-gray-600">Last active: just now</p>
          </div>
        </div>
      </div>
    </div>
  );
}
